 import type { 
@@
 } from "../providers/types.ts";
+
+const EMPTY_DELEGATION_RESULT = "Sub-agent completed without textual output.";
+
+interface DelegationToolInput {
+  agent_id?: unknown;
+  instructions?: unknown;
+}
+
+interface DelegationResult {
+  content: string;
+  isError: boolean;
+}
+
+function isDelegateTask(response: ProviderResponse): boolean {
+  return response.type === "tool_use" && response.toolName === "delegate_task";
+}
+
+function getDelegationInput(input: unknown): {
+  agentId: string;
+  instructions: string;
+} | null {
+  if (!input || typeof input !== "object") return null;
+
+  const { agent_id, instructions } = input as DelegationToolInput;
+  if (typeof agent_id !== "string" || typeof instructions !== "string") {
+    return null;
+  }
+
+  return { agentId: agent_id, instructions };
+}
+
+function createToolUseId(response: ProviderResponse): string {
+  if (response.toolUseId) return response.toolUseId;
+  const input = response.toolInput as { tool_use_id?: unknown } | undefined;
+  if (typeof input?.tool_use_id === "string") return input.tool_use_id;
+  return `delegate_task_${crypto.randomUUID()}`;
+}
+
+function createToolUseStreamResponse(
+  response: ProviderResponse,
+  toolUseId: string,
+  sessionId?: string
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        id: `msg_${toolUseId}`,
+        type: "message",
+        role: "assistant",
+        content: [{
+          type: "tool_use",
+          id: toolUseId,
+          name: response.toolName,
+          input: response.toolInput,
+        }],
+        stop_reason: "tool_use",
+        stop_sequence: null,
+      },
+      parent_tool_use_id: null,
+      session_id: sessionId,
+    },
+  };
+}
+
+function createToolResultStreamResponse(
+  toolUseId: string,
+  result: DelegationResult,
+  sessionId?: string
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "user",
+      message: {
+        role: "user",
+        content: [{
+          type: "tool_result",
+          is_error: result.isError,
+          content: result.content,
+          tool_use_id: toolUseId,
+        }],
+      },
+      parent_tool_use_id: null,
+      session_id: sessionId,
+    },
+  };
+}
