+/**
+ * Run a delegated agent without exposing its text as a separate chat turn.
+ * Its accumulated text becomes the parent tool result; nested tool calls are
+ * still streamed so every tool_result has its corresponding tool_use event.
+ */
+async function* runDelegatedAgent(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[]
+): AsyncGenerator<StreamResponse, DelegationResult> {
+  if (delegationPath.includes(agentId)) {
+    yield { type: "error", error: `circular delegation detected for agent '${agentId}'` };
+    return { isError: true, content: `circular delegation detected for agent '${agentId}'` };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    const content = `Agent '${agentId}' not found or provider not available`;
+    yield { type: "error", error: content };
+    return { isError: true, content };
+  }
+
+  const context: NonNullable<ProviderChatRequest["context"]> = [];
+  let accumulatedText = "";
+
+  try {
+    while (true) {
+      let shouldResume = false;
+      const providerRequest: ProviderChatRequest = {
+        message: instructions,
+        sessionId: request.sessionId,
+        requestId: request.requestId,
+        workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+        ...(context.length ? { context } : {}),
+      };
+
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          const content = response.content || "";
+          accumulatedText += content;
+          context.push({ role: "assistant", content });
+        } else if (isDelegateTask(response)) {
+          const toolUseId = createToolUseId(response);
+          yield createToolUseStreamResponse(response, toolUseId, request.sessionId);
+          const delegation = getDelegationInput(response.toolInput);
+          let nestedResult: DelegationResult;
+          if (!delegation) {
+            nestedResult = {
+              isError: true,
+              content: "delegate_task requires string agent_id and instructions fields.",
+            };
+          } else {
+            const nestedRun = runDelegatedAgent(
+              delegation.agentId,
+              delegation.instructions,
+              request,
+              abortController,
+              debugMode,
+              [...delegationPath, agentId]
+            );
+            while (true) {
+              const next = await nestedRun.next();
+              if (next.done) {
+                nestedResult = next.value;
+                break;
+              }
+              yield next.value;
+            }
+          }
+
+          yield createToolResultStreamResponse(toolUseId, nestedResult, request.sessionId);
+          context.push({
+            role: "user",
+            content: JSON.stringify({
+              type: "tool_result",
+              is_error: nestedResult.isError,
+              content: nestedResult.content,
+              tool_use_id: toolUseId,
+            }),
+          });
+          shouldResume = true;
+          break;
+        } else if (response.type === "error") {
+          return { isError: true, content: response.error || "Sub-agent run failed." };
+        } else if (response.type === "done") {
+          return { isError: false, content: accumulatedText || EMPTY_DELEGATION_RESULT };
+        }
+      }
+
+      if (!shouldResume) {
+        return { isError: false, content: accumulatedText || EMPTY_DELEGATION_RESULT };
+      }
+    }
+  } catch (error) {
+    return {
+      isError: true,
+      content: error instanceof Error ? error.message : String(error),
+    };
+  }
+}
