+const EMPTY_DELEGATION_RESULT = "Sub-agent completed without textual output.";
+
+interface DelegationToolInput {
+  agent_id?: unknown;
+  instructions?: unknown;
+}
+
+interface DelegationResult {
+  content: string;
+  isError: boolean;
+}
+
+function isDelegateTask(response: ProviderResponse): boolean {
+  return response.type === "tool_use" && response.toolName === "delegate_task";
+}
+
+function getDelegationInput(input: unknown): {
+  agentId: string;
+  instructions: string;
+} | null {
+  if (!input || typeof input !== "object") return null;
+
+  const { agent_id, instructions } = input as DelegationToolInput;
+  if (typeof agent_id !== "string" || typeof instructions !== "string") {
+    return null;
+  }
+
+  return { agentId: agent_id, instructions };
+}
+
+function createToolUseId(response: ProviderResponse): string {
+  if (response.toolUseId) return response.toolUseId;
+  const input = response.toolInput as { tool_use_id?: unknown } | undefined;
+  if (typeof input?.tool_use_id === "string") return input.tool_use_id;
